# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Initialize AWS clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# Environment variables
OUTPUT_BUCKET = os.environ.get('OUTPUT_BUCKET', 'image-processor-output')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')
SUPPORTED_FORMATS = {'.jpg', '.jpeg', '.png', '.gif', '.bmp', '.webp', '.tiff'}


class ImageProcessingError(Exception):
    """Custom exception for image processing errors."""
    pass


def validate_image_key(key):
    """Validate that the S3 key refers to a supported image format."""
    lower_key = key.lower()
    for fmt in SUPPORTED_FORMATS:
        if lower_key.endswith(fmt):
            return True
    return False


def get_image_from_s3(bucket, key):
    """
    Download an image from S3.

    Args:
        bucket: S3 bucket name
        key: S3 object key

    Returns:
        dict with image body bytes and metadata
    """
    logger.info(f"Fetching image from s3://{bucket}/{key}")
    try:
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response['Body'].read()
        content_type = response.get('ContentType', 'application/octet-stream')
        metadata = response.get('Metadata', {})
        content_length = response.get('ContentLength', 0)

        logger.info(
            f"Successfully fetched image: size={content_length} bytes, "
            f"content_type={content_type}"
        )

        return {
            'body': image_data,
            'content_type': content_type,
            'metadata': metadata,
            'content_length': content_length,
            'bucket': bucket,
            'key': key,
        }
    except s3_client.exceptions.NoSuchKey:
        logger.error(f"Image not found: s3://{bucket}/{key}")
        raise ImageProcessingError(f"Image not found: s3://{bucket}/{key}")
    except s3_client.exceptions.NoSuchBucket:
        logger.error(f"Bucket not found: {bucket}")
        raise ImageProcessingError(f"Bucket not found: {bucket}")
    except Exception as e:
        logger.error(f"Error fetching image from S3: {str(e)}")
        raise


def process_image(image_data):
    """
    Process the image data. This is the core processing logic.

    For MVP, this performs basic analysis. Extend this function
    for more sophisticated processing (e.g., resizing, thumbnails,
    label detection, etc.)

    Args:
        image_data: dict containing image body and metadata

    Returns:
        dict with processing results
    """
    logger.info("Starting image processing")

    image_bytes = image_data['body']
    file_size = len(image_bytes)
    key = image_data['key']
    filename = key.split('/')[-1]
    file_extension = os.path.splitext(filename)[1].lower()

    # Basic image analysis
    processing_result = {
        'original_key': key,
        'original_bucket': image_data['bucket'],
        'filename': filename,
        'file_extension': file_extension,
        'file_size_bytes': file_size,
        'content_type': image_data['content_type'],
        'processing_timestamp': datetime.utcnow().isoformat() + 'Z',
        'processing_id': str(uuid.uuid4()),
        'status': 'processed',
        'original_metadata': image_data['metadata'],
    }

    # Detect basic image properties from header bytes
    image_info = detect_image_properties(image_bytes)
    processing_result.update(image_info)

    # Placeholder for additional processing steps:
    # - Thumbnail generation (using Pillow in a Lambda layer)
    # - Image resizing
    # - EXIF data extraction
    # - Content moderation (via Rekognition)
    # - Label detection (via Rekognition)
    # - Face detection (via Rekognition)
    # - OCR / text extraction (via Textract)

    logger.info(
        f"Image processing complete: processing_id={processing_result['processing_id']}"
    )

    return processing_result


def detect_image_properties(image_bytes):
    """
    Detect basic image properties from the raw bytes.

    Args:
        image_bytes: raw image bytes

    Returns:
        dict with detected properties
    """
    properties = {}

    # PNG detection
    if image_bytes[:8] == b'\x89PNG\r\n\x1a\n':
        properties['detected_format'] = 'PNG'
        if len(image_bytes) >= 24:
            width = int.from_bytes(image_bytes[16:20], byteorder='big')
            height = int.from_bytes(image_bytes[20:24], byteorder='big')
            properties['width'] = width
            properties['height'] = height

    # JPEG detection
    elif image_bytes[:2] == b'\xff\xd8':
        properties['detected_format'] = 'JPEG'
        # Parse JPEG for dimensions (simplified SOF0 marker search)
        properties.update(_parse_jpeg_dimensions(image_bytes))

    # GIF detection
    elif image_bytes[:6] in (b'GIF87a', b'GIF89a'):
        properties['detected_format'] = 'GIF'
        if len(image_bytes) >= 10:
            width = int.from_bytes(image_bytes[6:8], byteorder='little')
            height = int.from_bytes(image_bytes[8:10], byteorder='little')
            properties['width'] = width
            properties['height'] = height

    # BMP detection
    elif image_bytes[:2] == b'BM':
        properties['detected_format'] = 'BMP'
        if len(image_bytes) >= 26:
            width = int.from_bytes(image_bytes[18:22], byteorder='little')
            height = abs(int.from_bytes(image_bytes[22:26], byteorder='little', signed=True))
            properties['width'] = width
            properties['height'] = height

    # WebP detection
    elif image_bytes[:4] == b'RIFF' and image_bytes[8:12] == b'WEBP':
        properties['detected_format'] = 'WebP'

    else:
        properties['detected_format'] = 'unknown'

    return properties


def _parse_jpeg_dimensions(image_bytes):
    """Parse JPEG bytes to extract image dimensions from SOF markers."""
    result = {}
    i = 2
    while i < len(image_bytes) - 1:
        if image_bytes[i] != 0xFF:
            break
        marker = image_bytes[i + 1]
        # SOF0 through SOF3 markers contain dimensions
        if marker in (0xC0, 0xC1, 0xC2, 0xC3):
            if i + 9 < len(image_bytes):
                height = int.from_bytes(image_bytes[i + 5:i + 7], byteorder='big')
                width = int.from_bytes(image_bytes[i + 7:i + 9], byteorder='big')
                result['width'] = width
                result['height'] = height
            break
        elif marker == 0xD9:  # EOI
            break
        elif marker in (0xD0, 0xD1, 0xD2, 0xD3, 0xD4, 0xD5, 0xD6, 0xD7, 0xD8, 0x01):
            i += 2
        else:
            if i + 3 < len(image_bytes):
                length = int.from_bytes(image_bytes[i + 2:i + 4], byteorder='big')
                i += 2 + length
            else:
                break
    return result


def write_results_to_s3(processing_result, processed_image_bytes=None):
    """
    Write processing results and optionally processed image to S3.

    Args:
        processing_result: dict with processing results
        processed_image_bytes: optional bytes of processed image

    Returns:
        dict with output S3 locations
    """
    processing_id = processing_result['processing_id']
    original_key = processing_result['original_key']
    timestamp = datetime.utcnow().strftime('%Y/%m/%d')

    output_locations = {}

    # Write JSON results
    results_key = f"results/{timestamp}/{processing_id}/metadata.json"
    logger.info(f"Writing results to s3://{OUTPUT_BUCKET}/{results_key}")

    try:
        s3_client.put_object(
            Bucket=OUTPUT_BUCKET,
            Key=results_key,
            Body=json.dumps(processing_result, indent=2, default=str),
            ContentType='application/json',
            Metadata={
                'processing-id': processing_id,
                'original-key': original_key,
            }
        )
        output_locations['results_key'] = results_key
        logger.info(f"Successfully wrote results to s3://{OUTPUT_BUCKET}/{results_key}")
    except Exception as e:
        logger.error(f"Error writing results to S3: {str(e)}")
        raise

    # Write processed image if provided
    if processed_image_bytes:
        filename = processing_result.get('filename', 'processed_image')
        processed_key = f"processed/{timestamp}/{processing_id}/{filename}"
        logger.info(f"Writing processed image to s3://{OUTPUT_BUCKET}/{processed_key}")

        try:
            s3_client.put_object(
                Bucket=OUTPUT_BUCKET,
                Key=processed_key,
                Body=processed_image_bytes,
                ContentType=processing_result.get('content_type', 'application/octet-stream'),
                Metadata={
                    'processing-id': processing_id,
                    'original-key': original_key,
                }
            )
            output_locations['processed_image_key'] = processed_key
            logger.info(f"Successfully wrote processed image to s3://{OUTPUT_BUCKET}/{processed_key}")
        except Exception as e:
            logger.error(f"Error writing processed image to S3: {str(e)}")
            raise

    return output_locations


def send_notification(processing_result, output_locations, status='SUCCESS'):
    """
    Send SNS notification about processing completion.

    Args:
        processing_result: dict with processing results
        output_locations: dict with S3 output locations
        status: processing status string
    """
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured, skipping notification")
        return

    processing_id = processing_result.get('processing_id', 'unknown')
    original_key = processing_result.get('original_key', 'unknown')

    subject = f"Image Processing {status}: {original_key}"

    message = {
        'status': status,
        'processing_id': processing_id,
        'original_image': {
            'bucket': processing_result.get('original_bucket'),
            'key': original_key,
        },
        'results': {
            'file_size_bytes': processing_result.get('file_size_bytes'),
            'detected_format': processing_result.get('detected_format'),
            'width': processing_result.get('width'),
            'height': processing_result.get('height'),
        },
        'output_locations': {
            'bucket': OUTPUT_BUCKET,
            **output_locations,
        },
        'timestamp': processing_result.get('processing_timestamp'),
    }

    logger.info(f"Sending SNS notification for processing_id={processing_id}")

    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],  # SNS subject max 100 chars
            Message=json.dumps(message, indent=2, default=str),
            MessageAttributes={
                'status': {
                    'DataType': 'String',
                    'StringValue': status,
                },
                'processing_id': {
                    'DataType': 'String',
                    'StringValue': processing_id,
                },
            }
        )
        logger.info(f"Successfully sent SNS notification for processing_id={processing_id}")
    except Exception as e:
        # Don't fail the whole process if notification fails
        logger.error(f"Error sending SNS notification: {str(e)}")


def send_error_notification(error_message, source_bucket=None, source_key=None):
    """
    Send SNS notification about processing failure.

    Args:
        error_message: error description
        source_bucket: source S3 bucket
        source_key: source S3 key
    """
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured, skipping error notification")
        return

    subject = f"Image Processing FAILED: {source_key or 'unknown'}"

    message = {
        'status': 'FAILED',
        'error': error_message,
        'source': {
            'bucket': source_bucket,
            'key': source_key,
        },
        'timestamp': datetime.utcnow().isoformat() + 'Z',
    }

    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],
            Message=json.dumps(message, indent=2, default=str),
            MessageAttributes={
                'status': {
                    'DataType': 'String',
                    'StringValue': 'FAILED',
                },
            }
        )
    except Exception as e:
        logger.error(f"Error sending error notification via SNS: {str(e)}")


def lambda_handler(event, context):
    """
    AWS Lambda handler for processing S3 image upload events.

    Triggered by S3 PUT events. Processes the uploaded image,
    writes results to the output bucket, and sends SNS notifications.

    Args:
        event: S3 event notification payload
        context: Lambda context object

    Returns:
        dict with processing summary
    """
    logger.info(f"Received event: {json.dumps(event, default=str)}")
    logger.info(
        f"Function: {context.function_name}, "
        f"Request ID: {context.aws_request_id}, "
        f"Remaining time: {context.get_remaining_time_in_millis()}ms"
    )

    results = []
    errors = []

    # Handle S3 event records (can contain multiple records)
    records = event.get('Records', [])

    if not records:
        logger.warning("No records found in event")
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'No records to process'}),
        }

    for record in records:
        source_bucket = None
        source_key = None

        try:
            # Extract S3 event information
            event_name = record.get('eventName', '')
            s3_info = record.get('s3', {})
            source_bucket = s3_info.get('bucket', {}).get('name')
            source_key = unquote_plus(s3_info.get('object', {}).get('key', ''))
            object_size = s3_info.get('object', {}).get('size', 0)

            logger.info(
                f"Processing record: event={event_name}, "
                f"bucket={source_bucket}, key={source_key}, "
                f"size={object_size}"
            )

            # Validate inputs
            if not source_bucket or not source_key:
                raise ImageProcessingError("Missing bucket or key in S3 event record")

            # Skip non-image files
            if not validate_image_key(source_key):
                logger.info(f"Skipping non-image file: {source_key}")
                results.append({
                    'key': source_key,
                    'status': 'skipped',
                    'reason': 'unsupported_format',
                })
                continue

            # Avoid processing our own output (prevent infinite loops)
            if source_bucket == OUTPUT_BUCKET:
                logger.warning(
                    f"Skipping file from output bucket to prevent loop: {source_key}"
                )
                continue

            # Step 1: Fetch image from S3
            image_data = get_image_from_s3(source_bucket, source_key)

            # Step 2: Process the image
            processing_result = process_image(image_data)

            # Step 3: Write results to output S3 bucket
            output_locations = write_results_to_s3(processing_result)

            # Step 4: Send success notification
            send_notification(processing_result, output_locations, status='SUCCESS')

            # Collect result
            result_summary = {
                'processing_id': processing_result['processing_id'],
                'source': f"s3://{source_bucket}/{source_key}",
                'status': 'success',
                'detected_format': processing_result.get('detected_format'),
                'dimensions': f"{processing_result.get('width', '?')}x{processing_result.get('height', '?')}",
                'output_bucket': OUTPUT_BUCKET,
                'output_locations': output_locations,
            }
            results.append(result_summary)

            logger.info(
                f"Successfully processed image: "
                f"processing_id={processing_result['processing_id']}, "
                f"source=s3://{source_bucket}/{source_key}"
            )

        except ImageProcessingError as e:
            error_msg = f"Image processing error: {str(e)}"
            logger.error(error_msg)
            errors.append({
                'source': f"s3://{source_bucket}/{source_key}" if source_bucket and source_key else 'unknown',
                'error': str(e),
                'error_type': 'ImageProcessingError',
            })
            send_error_notification(str(e), source_bucket, source_key)

        except Exception as e:
            error_msg = f"Unexpected error processing record: {str(e)}"
            logger.error(error_msg, exc_info=True)
            errors.append({
                'source': f"s3://{source_bucket}/{source_key}" if source_bucket and source_key else 'unknown',
                'error': str(e),
                'error_type': type(e).__name__,
            })
            send_error_notification(str(e), source_bucket, source_key)

    # Build response
    response = {
        'statusCode': 200,
        'body': {
            'message': f"Processed {len(results)} image(s) with {len(errors)} error(s)",
            'request_id': context.aws_request_id,
            'results': results,
            'errors': errors,
        }
    }

    logger.info(f"Lambda execution complete: {json.dumps(response, default=str)}")

    return response